import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import MapComponent from '../components/MapComponent';
import './PostJob.css';

const PostJob = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: 'painting',
    jobType: 'single-worker',
    requiredSkills: [],
    workersNeeded: 1,
    needsExpert: false,
    location: {
      address: '',
      city: '',
      state: '',
      pincode: '',
      coordinates: { latitude: null, longitude: null }
    },
    duration: {
      estimated: 1,
      unit: 'days'
    },
    urgency: 'medium'
  });

  const [mapPosition, setMapPosition] = useState({ lat: 20.5937, lng: 78.9629 });
  const [isMapVisible, setIsMapVisible] = useState(false);

  const [estimation, setEstimation] = useState(null);
  const [skillInput, setSkillInput] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const categories = [
    { id: 'painting', label: 'Painting', icon: '🎨' },
    { id: 'electrical', label: 'Electrical', icon: '⚡' },
    { id: 'masonry', label: 'Masonry', icon: '🧱' },
    { id: 'plumbing', label: 'Plumbing', icon: '🚰' },
    { id: 'carpentry', label: 'Carpentry', icon: '🪚' },
    { id: 'welding', label: 'Welding', icon: '🔥' },
    { id: 'construction', label: 'Construction', icon: '🏗️' },
    { id: 'cleaning', label: 'Cleaning', icon: '🧹' },
    { id: 'gardening', label: 'Gardening', icon: '🌱' },
    { id: 'loading', label: 'Loading', icon: '📦' },
    { id: 'fabrication', label: 'Fabrication', icon: '🛠️' },
    { id: 'tiling', label: 'Tiling', icon: '📐' },
    { id: 'other', label: 'Other', icon: '🛠️' }
  ];

  useEffect(() => {
    const fetchEstimation = async () => {
      if (formData.category && formData.workersNeeded) {
        try {
          const res = await api.post('/jobs/estimate', formData);
          setEstimation(res.data.estimation);
        } catch (err) {
          console.error(err);
        }
      }
    };
    fetchEstimation();
  }, [formData.category, formData.workersNeeded, formData.duration, formData.needsExpert]);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData({
        ...formData,
        [parent]: { ...formData[parent], [child]: value }
      });
    } else {
      setFormData({
        ...formData,
        [name]: type === 'checkbox' ? checked : value
      });
    }
  };

  const handleMapLocationChange = (position) => {
    setMapPosition(position);
    setFormData(prev => ({
      ...prev,
      location: {
        ...prev.location,
        coordinates: {
          latitude: position.lat,
          longitude: position.lng
        }
      }
    }));
  };

  const handleGeocode = async () => {
    if (!formData.location.address) {
      alert('Please enter an address first');
      return;
    }

    try {
      const response = await api.post('/location/geocode', {
        address: `${formData.location.address}, ${formData.location.city}, ${formData.location.state}, ${formData.location.pincode}`.replace(/, ,/g, ', ').replace(/, $/, '')
      });
      
      if (response.data.success) {
        const { latitude, longitude } = response.data.data;
        setMapPosition({ lat: latitude, lng: longitude });
        setFormData(prev => ({
          ...prev,
          location: {
            ...prev.location,
            coordinates: { latitude, longitude }
          }
        }));
        setIsMapVisible(true);
        alert('Address located on map successfully!');
      }
    } catch (error) {
      alert('Error geocoding address: ' + (error.response?.data?.message || error.message));
    }
  };

  const addSkill = (e) => {
    e.preventDefault();
    if (skillInput && !formData.requiredSkills.includes(skillInput)) {
      setFormData({
        ...formData,
        requiredSkills: [...formData.requiredSkills, skillInput]
      });
      setSkillInput('');
    }
  };

  const removeSkill = (skill) => {
    setFormData({
      ...formData,
      requiredSkills: formData.requiredSkills.filter(s => s !== skill)
    });
  };

  const analyzeJobWithAI = async () => {
    if (!formData.description.trim()) {
      alert('Please enter a job description first');
      return;
    }
    
    setIsAnalyzing(true);
    try {
      const response = await api.post('/ai/analyze-job-description', {
        description: formData.description
      });
      
      if (response.data.success) {
        setAiAnalysis(response.data.analysis);
        
        // Update form data with AI suggestions
        setFormData(prev => ({
          ...prev,
          requiredSkills: [
            ...new Set([...prev.requiredSkills, ...response.data.analysis.skills])
          ],
          duration: {
            estimated: response.data.analysis.duration.estimated,
            unit: response.data.analysis.duration.unit
          },
          workersNeeded: response.data.analysis.estimated_workers
        }));
        
        alert('AI has analyzed your job description and updated the form!');
      }
    } catch (error) {
      console.error('AI Analysis Error:', error);
      alert('Error analyzing job with AI: ' + (error.response?.data?.message || error.message));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Validate that coordinates are provided if map is visible
    if (isMapVisible && (!formData.location.coordinates.latitude || !formData.location.coordinates.longitude)) {
      alert('Please select a location on the map or hide the map');
      return;
    }
    
    try {
      await api.post('/jobs', formData);
      alert('Job posted successfully!');
      navigate('/employer/dashboard');
    } catch (err) {
      alert(err.response?.data?.message || 'Failed to post job');
    }
  };

  return (
    <div className="post-job-container">
      <h1>Post a New Job</h1>
      <form onSubmit={handleSubmit} className="job-form">
        <div className="form-section">
          <h3>Service Type</h3>
          <div className="category-grid">
            {categories.map(cat => (
              <div 
                key={cat.id} 
                className={`category-item ${formData.category === cat.id ? 'selected' : ''}`}
                onClick={() => setFormData({...formData, category: cat.id})}
              >
                <span className="cat-icon">{cat.icon}</span>
                <span className="cat-label">{cat.label}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="form-grid">
          <div className="form-group">
            <label>Job Title</label>
            <input name="title" value={formData.title} onChange={handleChange} required placeholder="e.g. Need House Painting" />
          </div>
          <div className="form-group">
            <label>Workers Needed</label>
            <input type="number" name="workersNeeded" value={formData.workersNeeded} onChange={handleChange} min="1" required />
          </div>
          <div className="form-group">
            <label>Estimated Duration</label>
            <div className="duration-inputs">
              <input type="number" name="duration.estimated" value={formData.duration.estimated} onChange={handleChange} min="1" required />
              <select name="duration.unit" value={formData.duration.unit} onChange={handleChange}>
                <option value="hours">Hours</option>
                <option value="days">Days</option>
                <option value="weeks">Weeks</option>
              </select>
            </div>
          </div>
          <div className="form-group">
            <label>Urgency</label>
            <select name="urgency" value={formData.urgency} onChange={handleChange}>
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
            </select>
          </div>
        </div>

        <div className="form-group">
          <div className="flex-between">
            <label>Description</label>
            <button 
              type="button" 
              onClick={analyzeJobWithAI}
              disabled={isAnalyzing || !formData.description.trim()}
              className="ai-analyze-btn"
            >
              {isAnalyzing ? 'Analyzing...' : '🤖 Analyze with AI'}
            </button>
          </div>
          <textarea name="description" value={formData.description} onChange={handleChange} required rows="4" placeholder="Describe the work details..."></textarea>
          
          {aiAnalysis && (
            <div className="ai-analysis-results">
              <h4>AI Analysis:</h4>
              <p><strong>Skills Identified:</strong> {aiAnalysis.skills.join(', ')}</p>
              <p><strong>Difficulty:</strong> {aiAnalysis.difficulty}</p>
              <p><strong>Materials Needed:</strong> {aiAnalysis.materials_needed.join(', ')}</p>
            </div>
          )}
        </div>

        <div className="form-group">
          <label>Required Skills (Optional)</label>
          <div className="skill-input-container">
            <input value={skillInput} onChange={(e) => setSkillInput(e.target.value)} placeholder="Add a specific skill" />
            <button type="button" onClick={addSkill}>Add</button>
          </div>
          <div className="skill-tags">
            {formData.requiredSkills.map(skill => (
              <span key={skill} className="skill-tag">
                {skill} <button type="button" onClick={() => removeSkill(skill)}>×</button>
              </span>
            ))}
          </div>
        </div>

        <div className="form-section checkbox-section">
          <label className="checkbox-label">
            <input type="checkbox" name="needsExpert" checked={formData.needsExpert} onChange={handleChange} />
            Require Expert-led Guidance (Highly recommended for complex tasks)
          </label>
        </div>

        <div className="form-section">
          <h3>Location Details</h3>
          <div className="form-grid">
            <input name="location.address" value={formData.location.address} onChange={handleChange} required placeholder="Address" />
            <input name="location.city" value={formData.location.city} onChange={handleChange} required placeholder="City" />
            <input name="location.state" value={formData.location.state} onChange={handleChange} required placeholder="State" />
            <input name="location.pincode" value={formData.location.pincode} onChange={handleChange} required placeholder="Pincode" />
          </div>
          <div className="location-actions">
            <button type="button" onClick={handleGeocode} className="geocode-btn">
              📍 Locate on Map
            </button>
            <button 
              type="button" 
              onClick={() => setIsMapVisible(!isMapVisible)}
              className="toggle-map-btn"
            >
              {isMapVisible ? 'Hide Map' : 'Show Map'}
            </button>
          </div>
          
          {isMapVisible && (
            <div className="map-container">
              <MapComponent 
                initialPosition={mapPosition} 
                onLocationChange={handleMapLocationChange}
                height="300px"
              />
              <div className="coordinates-display">
                Selected Coordinates: {formData.location.coordinates.latitude?.toFixed(6)}, {formData.location.coordinates.longitude?.toFixed(6)}
              </div>
            </div>
          )}
        </div>

        {estimation && (
          <div className="estimation-card">
            <h3>Estimated Cost: ₹{estimation.totalEstimated}</h3>
            <div className="estimation-breakdown">
              {estimation.breakdown.map((item, i) => (
                <div key={i} className="breakdown-item">
                  <span>{item.description}</span>
                  <span>₹{item.amount}</span>
                </div>
              ))}
            </div>
            <p className="estimation-note">* This is an intelligent estimate. Actual rates may be negotiated with workers.</p>
          </div>
        )}

        <button type="submit" className="submit-btn">Post Job & Match Workers</button>
        <p className="location-note">Note: Select a location on the map to improve worker matching accuracy</p>
      </form>
    </div>
  );
};

export default PostJob;
